module RefModule (
    input [3:0] A,
    input [3:0] B,
    input [3:0] Cin,
    output [3:0] S,
    output [3:0] C
);
    wire [3:0] S_temp;
    wire [3:0] C_temp;

    assign C_temp = (A & B) | (B & Cin) | (Cin & A); // Sum bits
    assign S_temp = A ^ B ^ Cin; // Carry bits

    assign S = S_temp;
    assign C = C_temp;

endmodule
